type NameHeadingProps = {
  names: string[];
  gap?: string;
};

export default function NameHeading({ names, gap = "0px" }: NameHeadingProps) {
  return (
    <div className="flex flex-col" style={{ gap }}>
      {names.map((name) => (
        <h1
          key={name}
          className="ml-[0.5vw] md:text-[6vw] font-archivo font-bold text-black text-left origin-top scale-y-[3] leading-[0.8]"
        >
          {name}
        </h1>
      ))}
    </div>
  );
}
